    "setupSql": "CREATE TABLE orders (id INTEGER, order_date TEXT);\nINSERT INTO orders (id, order_date) VALUES\n  (1, '2024-04-01'),\n  (2, '2024-05-15'),\n  (3, '2024-05-16'),\n  (4, '2024-05-30'),\n  (5, '2024-06-14'),\n  (6, '2024-06-15'),\n  (7, '2024-06-20');",
